      "policy_id": "POL-123",
      "claimant_name": "Robert Miller",
      "status": "SUBMITTED"
    }
  },
  "get_incident_details": {
    "description": "Retrieves specific data regarding the reported incident, including catastrophe codes, property descriptions, and reported damage estimates.",
    "parameters": {
      "type": "object",
      "properties": {
