    "parameters": {
      "type": "object",
      "properties": {
        "claim_id": {
          "type": "string",
          "description": "The unique identifier for the claim."
        }
      },
      "required": [
        "claim_id"
      ]
    },
    "example_output": {
      "documents": [
        {
          "doc_id": "D-001",
          "type": "FNOL",
          "verified": true
        },
        {
          "doc_id": "D-002",
          "type": "Adjuster_Report",
          "verified": false
