      ]
    }
  },
  "fetch_document_content": {
    "description": "Retrieves the text or data contents of a specific document in the registry (e.g., reading details from an Adjuster Report).",
    "parameters": {
      "type": "object",
      "properties": {
        "doc_id": {
          "type": "string",
          "description": "The unique identifier for the document."
        }
      },
      "required": [
        "doc_id"
      ]
    },
    "example_output": {
      "content_summary": "Adjuster confirms roof destruction. Estimated repair: $45,000. Displacement confirmed.",
      "verified_expenses": 1200.5
    }
  },
  "upload_claim_document": {
    "description": "Adds necessary documentation to the claim registry (e.g., submitting an adjuster's final assessment or ALE receipts).",
    "parameters": {
      "type": "object",
      "properties": {
        "claim_id": {
          "type": "string",
          "description": "The unique identifier for the claim."
        },
        "document_type": {
          "type": "string",
          "enum": [
            "Adjuster_Report",
            "ALE_Receipts",
            "Repair_Estimate"
          ],
          "description": "The type of document being uploaded."
        },
        "data_payload": {
          "type": "object",
          "description": "The structured data or content of the document."
        }
      },
      "required": [
        "claim_id",
        "document_type",
        "data_payload"
      ]
    },
    "example_output": {
      "doc_id": "D-003",
      "status": "UPLOADED"
    }
  },
  "set_internal_reserves": {
    "description": "Updates the financial log to set aside funds for indemnity and ALE based on calculations.",
    "parameters": {
      "type": "object",
      "properties": {
        "claim_id": {
          "type": "string",
          "description": "The unique identifier for the claim."
        },
        "indemnity_reserve": {
          "type": "number",
          "description": "Amount reserved for property damage."
        },
        "ale_reserve": {
          "type": "number",
          "description": "Amount reserved for living expenses."
        }
      },
      "required": [
        "claim_id",
        "indemnity_reserve",
        "ale_reserve"
      ]
    },
    "example_output": {
      "reserve_id": "RES-55",
      "total_allocated": 46200.5
