  "update_claim_status": {
    "description": "Advances the claim through lifecycle stages (e.g., TRIAGED, APPROVED, PAID).",
    "parameters": {
      "type": "object",
      "properties": {
        "claim_id": {
          "type": "string",
          "description": "The unique identifier for the claim."
        },
        "status": {
          "type": "string",
          "enum": [
            "TRIAGED",
            "UNDER_REVIEW",
            "APPROVED",
            "PAID"
          ]
        },
        "reasoning": {
          "type": "string",
          "description": "Explanation for the status change."
        }
      },
      "required": [
        "claim_id",
        "status"
      ]
    },
    "example_output": {
      "new_status": "APPROVED",
      "timestamp": "2024-09-01T10:00:00Z"
    }
  },
  "execute_disbursement": {
    "description": "Triggers the final financial payout to the claimant.",
    "parameters": {
      "type": "object",
      "properties": {
        "claim_id": {
          "type": "string",
          "description": "The unique identifier for the claim."
        },
        "payout_amount": {
          "type": "number",
          "description": "The total amount to be paid."
        },
        "auth_code": {
          "type": "string",
          "description": "Authorization code for the catastrophe event (e.g., PCS-24)."
        }
      },
      "required": [
        "claim_id",
        "payout_amount",
        "auth_code"
      ]
    },
    "example_output": {
      "transaction_id": "TXN-999",
      "status": "DISBURSED"
    }
  }
}
